100→      } else {
101→        onNavigate('recharge');
102→      }
103→    } else {
104→      onNavigate('login');
105→    }
106→  };
107→
108→  const plans = [
109→    {
110→      id: 1,
111→      name: "Le Jerrican",
112→      credits: 50,
113→      price: 15,
114→      icon: <Droplet size={24} />,
115→      popular: false,
116→      features: ["Id\u00e9al pour tester", "1 Audit complet", "Valable 1 an"]
117→    },
118→    {
119→      id: 2,
120→      name: "La Pompe",
121→      credits: 200,
122→      price: 49,
123→      icon: <Fuel size={24} />,
124→      popular: true,
125→      features: ["Pour optimiser s\u00e9rieusement", "Support prioritaire", "+10% Bonus offert"]
