 63→export const generateOptimizedRobotsTxt = (urlStr: string): string => {
 64→  let hostname = urlStr;
 65→  let protocol = 'https';
 66→  
 67→  try {
 68→    const urlObj = new URL(urlStr.startsWith('http') ? urlStr : `https://${urlStr}`);
 69→    hostname = urlObj.hostname;
 70→    protocol = urlObj.protocol.replace(':', '');
 71→  } catch (e) {
 72→    // Fallback if URL is invalid
 73→  }
 74→
 75→  const platform = detectPlatform(urlStr);
 76→  const date = new Date().toISOString().split('T')[0];
 77→
 78→  let content = `# Robots.txt Optimized for AEO (Answer Engine Optimization)
 79→# Generated by CitedBy.ai on ${date}
 80→# Domain: ${hostname}
 81→# Detected Architecture: ${platform.name}
 82→
 83→# ==========================================
 84→# PART 1: AI & LLM AGENTS (ALLOW LIST)
 85→# ==========================================
 86→# We explicitly allow these bots to ensure your content feeds 
 87→# the knowledge graphs of ChatGPT, Gemini, Claude, and Perplexity.
 88→`;
 89→
 90→  AI_BOTS.forEach(bot => {
 91→    content += `\nUser-agent: ${bot.agent}\n`;
 92→    content += `Allow: /\n`;
 93→    content += `# Purpose: ${bot.comment}\n`;
 94→  });
 95→
 96→  content += `
 97→# ==========================================
 98→# PART 2: GENERAL CRAWLERS & SEO
 99→# ==========================================
100→User-agent: *
101→Allow: /
102→
103→# --- Security & Privacy Protection ---
104→# Rules adapted for ${platform.name} structure
105→`;
106→
107→  platform.disallow.forEach(path => {
108→    content += `Disallow: ${path}\n`;
109→  });
110→
111→  content += `
112→# --- Sitemaps ---
113→# Provide clear paths for deep indexing
114→`;
115→
116→  platform.sitemaps.forEach(map => {
117→    content += `Sitemap: ${protocol}://${hostname}${map}\n`;
118→  });
119→
120→  content += `
121→# End of file
122→`;
123→
124→  return content;
125→};
